// // This module subtracts the second operand from the first operand when the operation selector is 00
module top_module(
    input [7:0] operand1,
    input [7:0] operand2,
    input [1:0] operation,
    output [7:0] result
);wire [8:0] sum;
wire [8:0] diff;

assign sum = operand1 + operand2;
assign diff = operand1 - operand2;

assign result = (operation == 2'b00) ? sum[7:0] : diff[7:0];

endmodule
